solution:
const fs = require('fs');

function streamFileToString(path) {
  return new Promise((resolve, reject) => {
    const stream = fs.createReadStream(path, { encoding: 'utf8' });
    let result = '';
    stream.on('data', (chunk) => {
      result += chunk;
    });
    stream.on('end', () => {
      resolve(result);
    });
    stream.on('error', reject);
  });
}

module.exports = { streamFileToString };
